namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut = new();

    private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.Name, Price = i.Price, Quantity = i.Qty }).ToList();

    // --- CreateOrder: Happy Path ---

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 3));

        // Act
        var order = _sut.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(30.00m, order.Total);
        Assert.AreEqual(1, order.Items.Count);
        Assert.IsFalse(string.IsNullOrEmpty(order.Id));
        Assert.IsTrue(order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_SumsTotalCorrectly()
    {
        // Arrange — two items: (5 * 2) + (3 * 4) = 22
        var items = CreateItems(("A", 5.00m, 2), ("B", 3.00m, 4));

        // Act
        var order = _sut.CreateOrder("cust-2", items);

        // Assert
        Assert.AreEqual(22.00m, order.Total);
        Assert.AreEqual(2, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_AssignsUniqueIds()
    {
        var items = CreateItems(("X", 1.00m, 1));

        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    // --- CreateOrder: Edge Cases ---

    [TestMethod]
    public void CreateOrder_ItemWithZeroQuantity_ReturnsZeroTotal()
    {
        var items = CreateItems(("Free", 99.99m, 0));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(0.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_ItemWithZeroPrice_ReturnsZeroTotal()
    {
        var items = CreateItems(("Freebie", 0.00m, 5));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(0.00m, order.Total);
    }

    // --- CreateOrder: Error Cases ---

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10.00m, 1));

        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(() => _sut.CreateOrder("cust-1", []));
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        var items = CreateItems(("Widget", 10.00m, 1));
        var created = _sut.CreateOrder("cust-1", items);

        var retrieved = _sut.GetOrder(created.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
        Assert.AreEqual(created.Total, retrieved.Total);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAll()
    {
        var items = CreateItems(("Widget", 5.00m, 1));
        _sut.CreateOrder("cust-A", items);
        _sut.CreateOrder("cust-A", items);
        _sut.CreateOrder("cust-B", items);

        var results = _sut.GetOrdersByCustomer("cust-A");

        Assert.AreEqual(2, results.Count);
        Assert.IsTrue(results.All(o => o.CustomerId == "cust-A"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var results = _sut.GetOrdersByCustomer("nobody");

        Assert.AreEqual(0, results.Count);
    }
}

